#include <stdio.h>
#include <stdlib.h>

// Define the structure for a node in the linked list
typedef struct Node {
    int key;
    int value;
    struct Node* prev;
    struct Node* next;
} Node;

// Define the structure for the LRU cache
typedef struct {
    int cap;
    int size;
    Node* head;
    Node* tail;
    Node** map;
} LruCache;

// Function to create a new node
Node* createNode(int key, int value) {
    Node* node = (Node*)malloc(sizeof(Node));
    node->key = key;
    node->value = value;
    node->prev = NULL;
    node->next = NULL;
    return node;
}

// Function to create the LRU cache
LruCache* createCache(int capacity) {
    LruCache* cache = (LruCache*)malloc(sizeof(LruCache));
    cache->cap = capacity;
    cache->size = 0;
    cache->head = NULL;
    cache->tail = NULL;
    cache->map = (Node**)calloc(10001, sizeof(Node*));
    return cache;
}

// Function to move a node to the front of the linked list
void moveToFront(LruCache* cache, Node* node) {
    if (cache->head == node) return;
    if (node->prev) node->prev->next = node->next;
    if (node->next) node->next->prev = node->prev;
    if (cache->tail == node) cache->tail = node->prev;
    node->prev = NULL;
    node->next = cache->head;
    if (cache->head) cache->head->prev = node;
    cache->head = node;
    if (!cache->tail) cache->tail = node;
}

// Function to get the value of a key
int getValue(LruCache* cache, int key) {
    Node* node = cache->map[key];
    if (!node) return -1;
    moveToFront(cache, node);
    return node->value;
}

// Function to put a key-value pair into the cache
void putValue(LruCache* cache, int key, int value) {
    Node* node = cache->map[key];
    if (node) {
        node->value = value;
        moveToFront(cache, node);
        return;
    }

    if (cache->size == cache->cap) {
        Node* lru = cache->tail;
        cache->map[lru->key] = NULL;
        cache->tail = lru->prev;
        if (cache->tail) cache->tail->next = NULL;
        else cache->head = NULL;
        free(lru);
        cache->size--;
    }

    Node* newNode = createNode(key, value);
    cache->map[key] = newNode;
    newNode->next = cache->head;
    if (cache->head) cache->head->prev = newNode;
    cache->head = newNode;
    if (!cache->tail) cache->tail = newNode;
    cache->size++;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int capacity;
        scanf("%d", &capacity);
        LruCache* cache = createCache(capacity);
        int Q;
        scanf("%d", &Q);
        while (Q--) {
            char op[4];
            scanf("%s", op);
            if (op[0] == 'g') {
                int key;
                scanf("%d", &key);
                printf("%d\n", getValue(cache, key));
            } else {
                int key, value;
                scanf("%d %d", &key, &value);
                putValue(cache, key, value);
                printf("None\n");
            }
        }
    }
    return 0;
}

